insert into public.posts (id,creator_id,topic,kind,image_url,bg_from,bg_to,caption,likes,comments,shares,age_hours,tiktok_url) values ('t10','tt_recipeincaption','cooking','tiktok',null,null,null,'Crispy Chicken Shawarma Wraps 🔥 For all of you asking about my recipe organizing app, search “Osta” on the app or google play store 🫶 Juicy chicken shawarma, creamy garlic sauce and crispy fries wrapped into one perfect bite 🌯 For the Chicken: insert into public.posts (id,creator_id,topic,kind,image_url,bg_from,bg_to,caption,likes,comments,shares,age_hours,tiktok_url) values ('t11','tt_thelittlechef74','cooking','tiktok',null,null,null,'Cacio e Pepe🇮🇹🧀 Ingredients (Serves 2) • 250g spaghetti or tonnarelli • 120g Pecorino Romano, finely grated • 2 tsp freshly cracked black pepper • Pasta water, reserved Instructions 1. Grate the cheese:     Finely grate the Pecorino Romano.     The finer the cheese, the smoother the sauce. 2. Cook the pasta:     Bring a large pot of salted water to a boil.     Cook the pasta until al dente.     Reserve at least 250ml of pasta water before draining. 3. Make the cheese cream:     Add a small amount of warm pasta water to the Pecorino Romano.     Whisk continuously.     Slowly add more water until you have a smooth, creamy sauce. 4. Toast the pepper:     Add the black pepper to a dry pan over medium heat.     Toast for 30–60 seconds until fragrant. 5. Build the sauce:     Add a splash of pasta water to the pan with the pepper.     Add the cooked pasta and toss well. 6. Combine:     Remove the pan from direct heat.     Add the Pecorino mixture and continue tossing.     Add more pasta water if needed until silky and glossy. 7. Serve:     Finish with extra Pecorino Romano.     Top with freshly cracked black pepper. #cacioepepesauce #cacioepepe #pastarecipes #dinnerideas #easyrecipes',15000,356,174,46,'https://www.tiktok.com/@the.little.chef74/video/7647604235298671894');
insert into public.posts (id,creator_id,topic,kind,image_url,bg_from,bg_to,caption,likes,comments,shares,age_hours,tiktok_url) values ('t12','tt_giovannisiracusaa','cooking','tiktok',null,null,null,'Crispy XL Pork Chops  🍋 Crispy, golden, and finished with a squeeze of fresh lemon. These breaded pork cutlets are easy to make and perfect for a weeknight dinner. Serve them with a simple salad and you''ve got a meal everyone will love.  Ingredients: Bone-in pork chops Flour Eggs Breadcrumbs Salt Frying oil Fresh lemon Directions: 1. Butterfly the pork chops by cutting them open without separating them completely. Pound them thin until evenly flattened. 2. Dredge each pork chop in flour, then egg, and finally breadcrumbs, pressing so the coating sticks. 3. Fry in hot oil for a few minutes per side until golden brown, crispy, and cooked through. 4. Transfer to a plate and season with salt while still hot. Serve with a squeeze of fresh lemon and a simple side salad. #pork #easyrecipe #fy',650000,14471,7224,30,'https://www.tiktok.com/@giovannisiracusaa/video/7649024510196337951');
