insert into public.posts (id,creator_id,topic,kind,image_url,bg_from,bg_to,caption,likes,comments,shares,age_hours,tiktok_url) values ('t22','tt_destinationinspiration','travel','tiktok',null,null,null,'Why is a weekend trip to Guatemala actually cheap? 🇬🇹🌋 2026 is the year we ALL start traveling more… Because one of the best adventures in the world is only a few hundred dollars and a long weekend away (weekendmaxing)  How to do this weekend trip (1.5 days of PTO): ✈️ Friday: Fly into Guatemala City ➡️ shuttle to Antigua 🥾 Saturday: Hike Acatenango + Fuego with OX Expeditions, camp on the volcano 🌄 Sunday: Sunrise above the clouds ➡️ hike down ➡️ spend the afternoon exploring Antigua Guatemala ✈️ Monday: Fly home Cost Breakdown: Flights: $250+ (found using @Skyscanner) Hostel: $42 (for 2 nights) Hike: $150 (with @oxexpeditions) Food: $35 Shuttle Bus: $40 Would you do this weekend trip? And if so… Where should the next adventure be? 🌍⬇️ #Guatemalatravel #Acatenango #FuegoVolcano #Weekendtrip #placestovisit',0,23,0,21,'https://www.tiktok.com/@destinationinspiration/video/7606390788867575071');
insert into public.posts (id,creator_id,topic,kind,image_url,bg_from,bg_to,caption,likes,comments,shares,age_hours,tiktok_url) values ('t23','tt_destinationinspiration','travel','tiktok',null,null,null,'Is this one of the most underrated countries in Europe? Or is that an exaggeration?  If you’re looking for a beautiful country in Europe but with fewer crowds, you NEED to add this to your bucket list. 📍 This is Montenegro 🇲🇪  A country in the Balkan region of Europe, Montenegro has something for everyone.  Looking for a seaside getaway? ✅ Maybe you want to go hiking through beautiful mountains? ✅  Want to get lost in historic villages? ✅  Montenegro travel itinerary: - Bay of Kotor - Perast - Rose - Budva - Sveti Stefan - Petrovac - Gusinje - Prokletije National park - Durmitor National Park The best part?  It''s more affordable and less crowded than other European countries like Italy, Croatia, and Greece. Let me know, would you visit Montenegro?? 🇲🇪  #montenegro #montenegro #montenegrotravel #traveltips #placestovisit',15000,357,173,35,'https://www.tiktok.com/@destinationinspiration/video/7554062370125942046');
